m, s = map(int, input().split())

if s == 0:
    if m == 1:
        print("0 0")
    else:
        print("-1 -1")
elif s > 9 * m:
    print("-1 -1")
else:
    # Construct the maximum number
    max_num = []
    remaining = s
    for _ in range(m):
        if remaining >= 9:
            max_num.append('9')
            remaining -= 9
        else:
            max_num.append(str(remaining))
            remaining = 0
    max_num = ''.join(max_num)

    # Construct the minimum number
    min_num = []
    remaining = s
    for i in range(m):
        # Determine the smallest digit possible at position i
        if i == 0:
            # First digit can't be zero
            lower = 1
        else:
            lower = 0
        # The remaining digits should be able to sum to remaining - d
        for d in range(lower, 10):
            if (remaining - d) <= 9 * (m - 1 - i):
                min_num.append(str(d))
                remaining -= d
                break
    min_num = ''.join(min_num)

    print(min_num, max_num)
